function M.GetAllVehicles()
    local vehicles = {}
    for _, class_label in ipairs(M.VehicleClasses_order) do
        for _, vehicle in ipairs(M.VehicleClasses[class_label]) do
            vehicles[#vehicles + 1] = vehicle
        end
    end
    return vehicles
end

